<#
Runs a GLPI Agent portable inventory from NinjaOne and uploads it to GLPI.

This script intentionally does not install the GLPI Agent Windows service. It
extracts or reuses the portable package, runs glpi-inventory, then pushes the
generated JSON with glpi-injector.
#>

$ErrorActionPreference = 'Stop'
Set-StrictMode -Version Latest

# Values intended to be generated by the GLPI plugin later.
$GlpiBaseUrl = 'https://support.tinisys.fr'
$GlpiInventoryUrl = ''
$InventoryTag = 'NinjaOne'
$AgentVersion = '1.17'
$AgentZipSource = 'https://github.com/glpi-project/glpi-agent/releases/download/1.17/GLPI-Agent-1.17-x64.zip'
$KeepSuccessfulInventories = $true
$DisableSslCheck = $false
$ProxyUrl = ''
$CaCertFile = ''
$SslFingerprint = ''

function Get-NinjaOneProgramFilesRoot {
    $programFilesX86 = [Environment]::GetEnvironmentVariable('ProgramFiles(x86)')
    if ([string]::IsNullOrWhiteSpace($programFilesX86)) {
        $programFilesX86 = ${env:ProgramFiles}
    }

    return Join-Path $programFilesX86 'NinjaOne'
}

function Write-RunLog {
    param(
        [Parameter(Mandatory = $true)]
        [string] $Message,

        [string] $Level = 'INFO'
    )

    $line = '{0} [{1}] {2}' -f (Get-Date -Format 'yyyy-MM-dd HH:mm:ss'), $Level, $Message
    Write-Output $line
    Add-Content -LiteralPath $script:LogFile -Value $line -Encoding UTF8
}

function ConvertTo-ProcessArgument {
    param([string] $Argument)

    if ($Argument -notmatch '[\s"]') {
        return $Argument
    }

    return '"' + ($Argument -replace '"', '\"') + '"'
}

function Invoke-LoggedProcess {
    param(
        [Parameter(Mandatory = $true)]
        [string] $FilePath,

        [Parameter(Mandatory = $true)]
        [string[]] $Arguments,

        [Parameter(Mandatory = $true)]
        [string] $WorkingDirectory,

        [bool] $LogStdOut = $true
    )

    $argumentLine = ($Arguments | ForEach-Object { ConvertTo-ProcessArgument $_ }) -join ' '
    Write-RunLog ("Running: {0} {1}" -f $FilePath, $argumentLine)

    $process = Start-Process `
        -FilePath $FilePath `
        -ArgumentList $argumentLine `
        -WorkingDirectory $WorkingDirectory `
        -NoNewWindow `
        -PassThru `
        -Wait `
        -RedirectStandardOutput $script:StdOutFile `
        -RedirectStandardError $script:StdErrFile

    if ($LogStdOut -and (Test-Path -LiteralPath $script:StdOutFile)) {
        Get-Content -LiteralPath $script:StdOutFile | ForEach-Object {
            if ($_ -ne '') {
                Write-RunLog $_ 'STDOUT'
            }
        }
    }

    if (Test-Path -LiteralPath $script:StdErrFile) {
        Get-Content -LiteralPath $script:StdErrFile | ForEach-Object {
            if ($_ -ne '') {
                Write-RunLog $_ 'STDERR'
            }
        }
    }

    if ($process.ExitCode -ne 0) {
        throw ("Process failed with exit code {0}: {1}" -f $process.ExitCode, $FilePath)
    }

    if (Test-Path -LiteralPath $script:StdErrFile) {
        $stderr = Get-Content -LiteralPath $script:StdErrFile -Raw
        if ($stderr -match '(?i)(file .+ does not exist|failed|fatal|error|bad request|not well formed|not sent)') {
            throw ("Process reported an error: {0}" -f ($stderr.Trim()))
        }
    }
}

function Resolve-InventoryUrl {
    if (-not [string]::IsNullOrWhiteSpace($script:GlpiInventoryUrl)) {
        return $script:GlpiInventoryUrl.Trim()
    }

    return $script:GlpiBaseUrl.TrimEnd('/') + '/front/inventory.php'
}

function Resolve-InventoryTag {
    $nodeId = [Environment]::GetEnvironmentVariable('NINJA_AGENT_NODE_ID')
    if (-not [string]::IsNullOrWhiteSpace($nodeId)) {
        return $script:InventoryTag + ':' + $nodeId.Trim()
    }

    return $script:InventoryTag
}

function Get-EnvironmentValue {
    param([string] $Name)

    $value = [Environment]::GetEnvironmentVariable($Name)
    if ($null -eq $value) {
        return ''
    }

    return $value
}

function Ensure-AgentPackage {
    param(
        [Parameter(Mandatory = $true)]
        [string] $ZipPath
    )

    if (Test-Path -LiteralPath $ZipPath) {
        Write-RunLog "Using existing GLPI Agent package: $ZipPath"
        return
    }

    if ([string]::IsNullOrWhiteSpace($script:AgentZipSource)) {
        throw "GLPI Agent package is missing. Place GLPI-Agent-$AgentVersion-x64.zip in the packages folder or set `$AgentZipSource."
    }

    if ($script:AgentZipSource -match '^https?://') {
        Write-RunLog "Downloading GLPI Agent package from $script:AgentZipSource"
        Invoke-WebRequest -Uri $script:AgentZipSource -OutFile $ZipPath -UseBasicParsing
        return
    }

    if (-not (Test-Path -LiteralPath $script:AgentZipSource)) {
        throw "Configured AgentZipSource does not exist: $script:AgentZipSource"
    }

    Write-RunLog "Copying GLPI Agent package from $script:AgentZipSource"
    Copy-Item -LiteralPath $script:AgentZipSource -Destination $ZipPath -Force
}

function Ensure-AgentExtracted {
    param(
        [Parameter(Mandatory = $true)]
        [string] $ZipPath,

        [Parameter(Mandatory = $true)]
        [string] $AgentDir
    )

    $inventoryBat = Join-Path $AgentDir 'glpi-inventory.bat'
    $injectorBat = Join-Path $AgentDir 'glpi-injector.bat'

    if ((Test-Path -LiteralPath $inventoryBat) -and (Test-Path -LiteralPath $injectorBat)) {
        Write-RunLog "Using existing extracted GLPI Agent portable folder: $AgentDir"
        return
    }

    if (Test-Path -LiteralPath $AgentDir) {
        Remove-Item -LiteralPath $AgentDir -Recurse -Force
    }

    New-Item -ItemType Directory -Path $AgentDir -Force | Out-Null
    Write-RunLog "Extracting GLPI Agent package to $AgentDir"
    Expand-Archive -LiteralPath $ZipPath -DestinationPath $AgentDir -Force

    if (-not (Test-Path -LiteralPath $inventoryBat)) {
        throw "glpi-inventory.bat was not found after extraction."
    }

    if (-not (Test-Path -LiteralPath $injectorBat)) {
        throw "glpi-injector.bat was not found after extraction."
    }
}

$ConnectorRoot = Join-Path (Get-NinjaOneProgramFilesRoot) 'plugin\glpi-connector'
$AgentDir = Join-Path $ConnectorRoot 'agent'
$InventoryRoot = Join-Path $ConnectorRoot 'inventories'
$PendingDir = Join-Path $InventoryRoot 'pending'
$SentDir = Join-Path $InventoryRoot 'sent'
$LogDir = Join-Path $ConnectorRoot 'logs'
$PackageDir = Join-Path $ConnectorRoot 'packages'

foreach ($dir in @($ConnectorRoot, $AgentDir, $InventoryRoot, $PendingDir, $SentDir, $LogDir, $PackageDir)) {
    New-Item -ItemType Directory -Path $dir -Force | Out-Null
}

$RunId = Get-Date -Format 'yyyyMMdd-HHmmss'
$HostSafe = ($env:COMPUTERNAME -replace '[^A-Za-z0-9_.-]', '_')
$script:LogFile = Join-Path $LogDir "$HostSafe-$RunId.log"
$script:StdOutFile = Join-Path $LogDir "$HostSafe-$RunId.stdout.tmp"
$script:StdErrFile = Join-Path $LogDir "$HostSafe-$RunId.stderr.tmp"

try {
    $zipPath = Join-Path $PackageDir "GLPI-Agent-$AgentVersion-x64.zip"
    $inventoryFile = Join-Path $PendingDir "$HostSafe-$RunId.json"
    $inventoryUrl = Resolve-InventoryUrl
    $resolvedInventoryTag = Resolve-InventoryTag

    Write-RunLog "GLPI portable inventory run started."
    Write-RunLog "Connector root: $ConnectorRoot"
    Write-RunLog "Inventory endpoint: $inventoryUrl"
    Write-RunLog "Inventory tag: $resolvedInventoryTag"
    Write-RunLog ("NinjaOne node ID: {0}" -f (Get-EnvironmentValue 'NINJA_AGENT_NODE_ID'))
    Write-RunLog ("NinjaOne machine ID: {0}" -f (Get-EnvironmentValue 'NINJA_AGENT_MACHINE_ID'))

    Ensure-AgentPackage -ZipPath $zipPath
    Ensure-AgentExtracted -ZipPath $zipPath -AgentDir $AgentDir

    $inventoryArgs = @('--json', '--tag', $resolvedInventoryTag)
    Invoke-LoggedProcess `
        -FilePath (Join-Path $AgentDir 'glpi-inventory.bat') `
        -Arguments $inventoryArgs `
        -WorkingDirectory $AgentDir `
        -LogStdOut $false

    if (Test-Path -LiteralPath $script:StdOutFile) {
        Copy-Item -LiteralPath $script:StdOutFile -Destination $inventoryFile -Force
    }

    if ((-not (Test-Path -LiteralPath $inventoryFile)) -or ((Get-Item -LiteralPath $inventoryFile).Length -le 0)) {
        throw "Inventory JSON was not generated."
    }

    $injectorArgs = @('-v', '-f', $inventoryFile, '--url', $inventoryUrl)
    if ($DisableSslCheck) {
        $injectorArgs += '--no-ssl-check'
    }
    if (-not [string]::IsNullOrWhiteSpace($ProxyUrl)) {
        $injectorArgs += @('--proxy', $ProxyUrl)
    }
    if (-not [string]::IsNullOrWhiteSpace($CaCertFile)) {
        $injectorArgs += @('--ca-cert-file', $CaCertFile)
    }
    if (-not [string]::IsNullOrWhiteSpace($SslFingerprint)) {
        $injectorArgs += @('--ssl-fingerprint', $SslFingerprint)
    }

    Invoke-LoggedProcess `
        -FilePath (Join-Path $AgentDir 'glpi-injector.bat') `
        -Arguments $injectorArgs `
        -WorkingDirectory $AgentDir

    if ($KeepSuccessfulInventories) {
        Move-Item -LiteralPath $inventoryFile -Destination (Join-Path $SentDir (Split-Path $inventoryFile -Leaf)) -Force
    } else {
        Remove-Item -LiteralPath $inventoryFile -Force
    }

    Write-RunLog "GLPI portable inventory run completed successfully."
    exit 0
} catch {
    Write-RunLog $_.Exception.Message 'ERROR'
    Write-RunLog "GLPI portable inventory run failed. Pending inventories are kept in $PendingDir." 'ERROR'
    exit 1
} finally {
    foreach ($tmpFile in @($script:StdOutFile, $script:StdErrFile)) {
        if (Test-Path -LiteralPath $tmpFile) {
            Remove-Item -LiteralPath $tmpFile -Force
        }
    }
}

